+fn make_signing_key(seed: u8) -> SigningKey {
+    let mut key = [0u8; 32];
+    for (index, byte) in key.iter_mut().enumerate() {
+        *byte = seed.wrapping_add(index as u8).wrapping_mul(7);
+    }
+    SigningKey::from_bytes(key)
+}
